        val assetLoader = getViewerAssetLoader(webviewDomain)
        val webView: WebView = MyWebView(this).apply {
            scrollBarStyle = View.SCROLLBARS_OUTSIDE_OVERLAY
            with(settings) {
                displayZoomControls = false
                builtInZoomControls = true
                setSupportZoom(true)
                loadWithOverviewMode = true
                javaScriptEnabled = true
                allowFileAccess = true
                // enable dom storage so that sessionStorage & localStorage can be used in webview
                domStorageEnabled = true
            }
            webChromeClient = AnkiDroidWebChromeClient()
            isFocusableInTouchMode = typeAnswer!!.useInputTag
            isScrollbarFadingEnabled = true
            // Set transparent color to prevent flashing white when night mode enabled
            setBackgroundColor(Color.argb(1, 0, 0, 0))
            CardViewerWebClient(assetLoader, this@AbstractFlashcardViewer).apply {
                webViewClient = this
                this@AbstractFlashcardViewer.webViewClient = this
            }
        }
        Timber.d(
            "Focusable = %s, Focusable in touch mode = %s",
            webView.isFocusable,
            webView.isFocusableInTouchMode
        )

        // enable third party cookies so that cookies can be used in webview
        CookieManager.getInstance().setAcceptThirdPartyCookies(webView, true)

        // Apply software rendering to WebView if preference is enabled
        // This fixes SVG CSS update rendering issues
        if (sharedPrefs().getBoolean("softwareRender", false)) {
            Timber.d("Setting WebView to software rendering mode for SVG compatibility")
            webView.setLayerType(View.LAYER_TYPE_SOFTWARE, null)
        }

        return webView
    }"}

